from __future__ import annotations

import csv
from pathlib import Path

ALLOWED_COLUMNS = [
    "step",
    "event",
    "birth_index",
    "birth_type",
    "death_index",
    "death_type",
    "mutants_before",
    "mutants_after",
    "N",
]


def build_system_prompt() -> str:
    return (
        "You are given an event history generated by a Moran birth-death process. "
        "Your task is to classify whether the fixation probability rho of the mutant type is greater than or less than 0.5. "
        "rho depends on the relative fitness r and initial mutant count i0 and population size N. "
        "A value of rho > 0.5 means mutants are more likely to fix than not (label X). "
        "A value of rho < 0.5 means mutants are less likely to fix than not (label O). "
        "To estimate rho, reason through the following steps explicitly before answering: "
        "Step 1: Estimate the population size N from the trace (it is constant, visible in the N column). "
        "Step 2: Estimate the initial mutant count i0 from the earliest mutants_before value in the trace. "
        "Step 3: Estimate the relative fitness r by computing the ratio of observed mutant birth rate "
        "to the expected mutant birth rate under neutrality (mutant fraction at each step). "
        "Step 4: Use the Moran fixation formula: rho = (1 - (1/r)^i0) / (1 - (1/r)^N). "
        "Step 5: If rho > 0.5 output X, if rho < 0.5 output O. "
        "Return valid JSON with exactly these keys: label (X or O), estimated_r, estimated_i0, rho_estimated, reasoning_summary. "
        "Do not output any other text outside the JSON."
    )


def _observable_csv_text(csv_path: Path) -> str:
    with csv_path.open("r", newline="", encoding="utf-8") as handle:
        reader = csv.DictReader(handle)
        rows = list(reader)

    for forbidden in ("true_i0", "true_r", "true_N", "meta_json"):
        if forbidden in (reader.fieldnames or []):
            raise ValueError(f"Forbidden ground-truth column found in trace CSV: {forbidden}")

    present_columns = [c for c in ALLOWED_COLUMNS if c in (reader.fieldnames or [])]
    output_lines = [",".join(present_columns)]
    for row in rows:
        output_lines.append(",".join(str(row[col]) for col in present_columns))
    return "\n".join(output_lines)


def build_user_prompt_from_csv(csv_path: str | Path) -> str:
    csv_path = Path(csv_path)
    return (
        f"Trace file: {csv_path.name}\n"
        "Below is the observable Moran-process event history in CSV format. "
        "Classify whether the fixation probability rho is greater than 0.5 (X) or less than 0.5 (O).\n\n"
        f"{_observable_csv_text(csv_path)}"
    )
